  # Helper to strip surrounding quotes from objects
      def _clean(obj: str) -> str:
          if len(obj) >= 2 and obj[0] == '"' and obj[-1] == '"':
              return obj[1:-1]
          return obj

      clauses = []
      for t in triples:
          tmpl = templates.get(t.predicate)
          obj = _clean(t.object)

          # Special handling for timeInSpace to present in hours instead of raw minutes
          if t.predicate == "timeInSpace":
              try:
                  minutes = float(obj.replace('"', '').replace("'", ""))
                  hours = minutes / 60
                  obj = f"{hours:.1f} hours"
              except Exception:
                  pass

          if tmpl:
              clause = tmpl.format(subject=t.subject, object=obj)
          else:
              # Fallback: make predicate readable
              pred = t.predicate.replace("_", " ")
              clause = f"{t.subject} {pred} {obj}"
          clauses.append(clause)
